  private get createDateStr(): string {
    document.title = `${this.illust.title}\x20-\x20${this.illust.user.name}`;
    const d = new Date(this.illust.upload_timestamp);
    return `${d.getFullYear()}年${d.getMonth() +
      1}月${d.getDate()}日${d.getHours()}时${d.getMinutes()}分${d.getSeconds()}秒`;
  }
  async syncDeatil() {
    try {
      const detail = await getIllustDetail();
      let url = new URL(detail.author_details.profile_img.main);
      if (url.pathname == '/common/images/no_profile.png') {
        url.href = 'https://s1.ax1x.com/2020/09/06/wmiAcd.png';
      } else {
        url.host = 'i.pixiv.cat';
      }
      const { user } = this.illust;
      user.profile_image_url = url.href;
      user.id = detail.author_details.user_id;
      user.name = detail.author_details.user_name;
      user.account = detail.author_details.user_account;
      Object.freeze(user);
      this.illust.id = detail.illust_details.id;
      this.illust.title = detail.illust_details.title;
      this.illust.upload_timestamp =
        detail.illust_details.upload_timestamp * 1000;
      this.illust.page_count = detail.illust_details.page_count;
      this.illust.tags = detail.illust_details.display_tags.map((t) => ({
        name: t.tag,
        translation: t.translation,
      }));
      this.illust.total_view = detail.illust_details.rating_view;
      this.illust.rating_count = detail.illust_details.rating_count;
      this.illust.total_bookmarks = detail.illust_details.bookmark_user_total.toString();
      this.illust.caption = detail.illust_details.comment_html;
      Object.freeze(this.illust);
    } finally {
      this.loadFinish = true;
    }
  }
  created() {
    this.syncDeatil();
  }
  private loadFinish = false;
}
