import { Base64 } from 'js-base64';
import { IllustDetailsResp, IllustData } from './types';
import pako from 'pako';
import Axios from 'axios';

let illust_id: string | null = null;
function getIllustInfoFromHash(): IllustData {
  let { hash } = location;
  if (hash.length < 10) {
    console.log(`hash: ${hash}`);
    console.log('location hash is not expected, use default value');
    hash =
      '#H4sIAAAAAAAAAA3JSQqAIBgG0Lt8axcOv+NVIkIcQjAIrJV493rbN9F6f8dztIzgBDltyTC0K56ltl4GwjbxHzJRTclEITlXSmjytopIsVrpMxkNhhuBr319cKHWIFQAAAA=';
    console.log(`default hash: ${hash}`);
  }
  const content: Uint8Array = Base64.toUint8Array(hash.substr(1));
  const illust: IllustData = JSON.parse(
    pako.inflate(content, { to: 'string' })
  );
  illust_id = illust.illust_id.toString();
  return illust;
}

async function getIllustDetail() {
  const url =
    'https://1887623261562936.cn-hongkong.fc.aliyuncs.com/2016-08-15/proxy/aliyun-severless-b395ab/www-pixiv-net/touch/ajax/illust/details';
  // 'https://app-api-pixiv-net.lisonge.workers.dev/v1/illust/detail';
  const resp = await Axios.get(url, {
    params: {
      illust_id,
      lang: 'zh',
    },
  });
  const { body } = resp.data as IllustDetailsResp;
  return body;
}

export { getIllustInfoFromHash, getIllustDetail };
